const b = $input.item.json.body || $input.item.json;
const action       = b.action       || 'denied';
const client_id    = b.client_id    || '';
const request_type = b.request_type || 'join';
if (!client_id) throw new Error('client_id mancante');
return [{ json: { action, client_id, request_type } }];

const rows = Array.isArray($input.item.json) ? $input.item.json : [$input.item.json];
const client = rows[0] || {};
const clientName  = [client.first_name, client.last_name].filter(Boolean).join(' ') || 'Cliente';
const clientEmail = client.email || '';
if (!clientEmail) throw new Error('Email cliente non trovata');
return [{ json: { clientName, clientEmail } }];

